import os
import sys
import tarfile
import shutil
import zipfile
import bz2
import subprocess


def compress(source, destination):
    """Compress the given source file to the destination file"""

    if os.path.exists(destination) and os.path.isfile(destination):
        print('File already exists')
        return False

    if not os.path.exists(source):
        print('Source file does not exist')
        return False

    if os.path.isdir(source):

        # Create a new tarfile
        tar = tarfile.open(destination, "w")

        try:
            tar.add(source)
            tar.close()

            print('Compression successful')
            return True

        except Exception as e:
            print("Error while compressing the file: {}".format(e))

    else:
        print('Source is not a directory or file')


def zip_dir(directory, ziph):
    """Zip the given source directory to the destination file"""

    try:
        for root, dirs, files in os.walk(directory):
            for file in files:
                ziph.write(os.path.join(root, file))

        print('Compression successful')
        return True

    except Exception as e:
        print("Error while compressing the file: {}".format(e))


def main():
    """Main function"""

    # Get the source and destination directories from command line arguments
    source = sys.argv[1]
    destination = sys.argv[2]

    # Check if the source directory exists
    if not os.path.exists(source):
        print('Source file does not exist')
        return False

    # Create a new zipfile for compression
    zipf = zipfile.ZipFile(destination, 'w', zipfile.ZIP_DEFLATED)

    try:

        # Compress the source directory using zip
        if os.path.isdir(source):
            zip_dir(source, zipf)

        else:

            # Get the file extension from the destination filename
            ext = os.path.splitext(destination)[1]

            # Check for supported compression formats and compress accordingly
            if ext == '.gz':
                with open(destination, 'wb') as f:
                    with gzip.open(source, 'rb') as source_file:
                        shutil.copyfileobj(source_file, f)

                print('Compression successful')
                return True

            elif ext in ['.bz2', '.tbz']:
                with open(destination, 'w') as f:
                    with bz2.open(f, 'wb') as source_file:
                        shutil.copyfileobj(source_file, f)

                print('Compression successful')
                return True

            elif ext == '.zip':
                zipf = zipfile.ZipFile(destination, 'w', zipfile.ZIP_DEFLATED)
                with open(destination, 'wb') as f:
                    shutil.copyfileobj(source_file, f)

                print('Compression successful')
                return True

            else:
                print('Unsupported compression format')

        # Close the zip file
        zipf.close()

    except Exception as e:
        print("Error while compressing the file: {}".format(e))


if __name__ == '__main__':
    main()